#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        char **A = (char**)malloc(N*sizeof(char*));
        char **B = (char**)malloc(N*sizeof(char*));
        for(int i=0;i<N;i++){
            A[i]= (char*)malloc(25);
            scanf("%s", A[i]);
        }
        for(int i=0;i<N;i++){
            B[i]= (char*)malloc(25);
            scanf("%s", B[i]);
        }
        int ok=1;
        long long cntA[10]={0}, cntB[10]={0};
        for(int i=0;i<N && ok;i++){
            if(strlen(A[i])!=strlen(B[i])) ok=0;
            for(char *p=A[i]; *p; ++p) cntA[*p-'0']++;
            for(char *p=B[i]; *p; ++p) cntB[*p-'0']++;
        }
        if(!ok){
            printf("NO\n");
            for(int i=0;i<N;i++){free(A[i]);free(B[i]);}
            free(A);free(B);
            continue;
        }
        long long need=0;
        for(int d=0;d<10;d++) if(cntB[d]>cntA[d]) need+=cntB[d]-cntA[d];
        printf(need<=K?"YES\n":"NO\n");
        for(int i=0;i<N;i++){free(A[i]);free(B[i]);}
        free(A);free(B);
    }
    return 0;
}

