import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long K = fs.nextLong();
            String[] A = new String[N];
            String[] B = new String[N];
            for (int i = 0; i < N; i++) A[i] = fs.next();
            for (int i = 0; i < N; i++) B[i] = fs.next();
            boolean ok = true;
            long[] cntA = new long[10];
            long[] cntB = new long[10];
            for (int i = 0; i < N && ok; i++) {
                if (A[i].length() != B[i].length()) ok = false;
                for (int j = 0; j < A[i].length(); j++) cntA[A[i].charAt(j) - '0']++;
                for (int j = 0; j < B[i].length(); j++) cntB[B[i].charAt(j) - '0']++;
            }
            if (!ok) {
                out.append("NO\n");
                continue;
            }
            long need = 0;
            for (int d = 0; d < 10; d++) if (cntB[d] > cntA[d]) need += cntB[d] - cntA[d];
            out.append(need <= K ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
    // Fast scanner for competitive programming
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        long nextLong() throws IOException { return Long.parseLong(next()); }
    }
}

