#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it)); K = int(next(it))
        A = [next(it) for _ in range(n)]
        B = [next(it) for _ in range(n)]
        possible = True
        cntA = [0]*10
        cntB = [0]*10
        for a,b in zip(A,B):
            if len(a)!=len(b):
                possible=False
                break
            for ch in a:
                cntA[ord(ch)-48] += 1
            for ch in b:
                cntB[ord(ch)-48] += 1
        if not possible:
            out_lines.append("NO")
            continue
        need = sum(max(0, cntB[d]-cntA[d]) for d in range(10))
        out_lines.append("YES" if need<=K else "NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

